@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam linetype ortho

class Capitan {
  nombre: String
  apellido: String
  matricula: int
  --
  Capitan(nombre String, apellido String, matricula int): void
}

interface Comparable {
  compareTo(o Object): int
}

abstract class Embarcacion {
  capitan: Capitan
  precioBase: double
  valorAdicional: double
  AñoDeFabricacion: int
  --
  montoDeAlquiler(): double
}

class Yate {
  cantCamarotes: int
  --
  compareTo(o Object): int
}

class Velero {
  cantMastiles: int
  --
  esGrande(): boolean
}

Embarcacion "1" --> "1" Capitan

Yate ..|> Comparable : implements
Yate --|> Embarcacion : extends
Velero --|> Embarcacion : extends
@enduml
